39	function computeBasePremium(items: Item[]): number {
40	  const countsByType: Record<string, number> = {};
41	  for (const item of items) {
42	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
43	  }
44	  let basePremium = 0;
45	  for (const [type, count] of Object.entries(countsByType)) {
46	    if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
47	      basePremium += COMPONENT_BLOCK_PRICE;
48	    } else {
49	      const perItem = BASE_PREMIUM[type] ?? 0;
50	      basePremium += perItem * count;
51	    }
52	  }
53	  return basePremium;
54	}
55	
56	function computeItemSurcharges(items: Item[]): number {
57	  let surcharges = 0;
58	  for (const item of items) {
59	    const itemBase = BASE_PREMIUM[item.type] ?? 0;
60	    if (item.cursed) {
61	      surcharges += itemBase * CURSED_SURCHARGE_RATE;
62	    }
63	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
64	      surcharges += itemBase * HIGH_ENCHANTMENT_RATE;
65	    }
66	  }
67	  return surcharges;
68	}
