70	export function runScenario(input: unknown): unknown {
71	  const scenario = input as Scenario;
72	  const results = scenario.steps.map((step, stepIndex) => {
73	    const basePremium = computeBasePremium(step.items);
74	    const itemSurcharges = computeItemSurcharges(step.items);
75	    const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
76	    const loyaltyDiscount =
77	      scenario.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
78	        ? basePremium * LOYALTY_DISCOUNT_RATE
79	        : 0;
80	    const followUpDiscount =
81	      stepIndex >= 1 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
82	    const rawPremium = basePremium + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
83	    const premium = Math.ceil(rawPremium);
84	    return { premium };
85	  });
86	  return { results };
87	}
