function computeQuote(
  step: QuoteStep,
  stepIndex: number,
  customer: Customer,
): { premium: number } {
  const basePremium = computeBasePremium(step.items);
  const itemSurcharges = computeItemSurcharges(step.items);
  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
